import boto3
import json
from typing import Dict, Any

class PIISQSPublisher:
    def __init__(self, queue_url: str, region_name: str = 'us-east-1'):
        self.queue_url = queue_url
        self.sqs = boto3.client('sqs', region_name=region_name)
    
    def send_user_data_message(self, user_data: Dict[str, Any]) -> Dict[str, Any]:
        """
        Send user data message to SQS queue
        :param user_data: Dictionary containing user information including PII
        :return: Response from SQS
        """
        try:
            # Prepare message body
            message_body = json.dumps(user_data)
            
            # Send message to SQS
            response = self.sqs.send_message(
                QueueUrl=self.queue_url,
                Message=message_body,
                MessageAttributes={
                    'MessageType': {
                        'StringValue': 'UserPIIData',
                        'DataType': 'String'
                    }
                }
            )
            
            return response
            
        except Exception as e:
            raise Exception(f"Failed to send message to SQS: {str(e)}")

